 1→export type ProgramType = 'stamp' | 'points';
 2→export type DiscountType = 'percentage' | 'fixed' | 'freebie';
 3→export type ValidationMethod = 'qr' | 'nfc' | 'manual';
 4→export type TransactionType = 'stamp_add' | 'points_add' | 'reward_redeem';
 5→export type CustomerTier = 'bronze' | 'silver' | 'gold' | 'vip';
 6→export type MerchantPlan = 'free' | 'pro' | 'business';
 7→export type CampaignStatus = 'draft' | 'scheduled' | 'sent' | 'cancelled';
 8→export type NotificationType = 'campaign' | 'reward_available' | 'expiration_warning' | 'proximity' | 'welcome' | 'referral';
 9→
10→export interface Merchant {
11→  id: string;
12→  name: string;
13→  logo_url: string | null;
14→  address: string | null;
15→  category: string | null;
16→  plan: MerchantPlan;
17→  subscription_status: string;
18→  stripe_customer_id: string | null;
19→  created_at: string;
