  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers':
  6→    'authorization, x-client-info, apikey, content-type, x-api-key',
  7→};
  8→
  9→async function hashKey(key: string): Promise<string> {
 10→  const encoder = new TextEncoder();
 11→  const data = encoder.encode(key);
 12→  const hash = await crypto.subtle.digest('SHA-256', data);
 13→  return Array.from(new Uint8Array(hash))
 14→    .map((b) => b.toString(16).padStart(2, '0'))
 15→    .join('');
 16→}
 17→
 18→Deno.serve(async (req) => {
 19→  if (req.method === 'OPTIONS') {
 20→    return new Response('ok', { headers: corsHeaders });
 21→  }
 22→
 23→  try {
 24→    const supabase = createClient(
 25→      Deno.env.get('SUPABASE_URL')!,
 26→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 27→    );
 28→
 29→    // Authenticate via API key
 30→    const apiKey = req.headers.get('X-API-Key');
 31→    if (!apiKey) {
 32→      return new Response(JSON.stringify({ error: 'Missing API key' }), {
 33→        status: 401,
 34→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
 35→      });
 36→    }
 37→
 38→    const keyHash = await hashKey(apiKey);
 39→    const { data: keyRecord } = await supabase
 40→      .from('api_keys')
 41→      .select('*, merchants(plan)')
 42→      .eq('key_hash', keyHash)
 43→      .eq('is_active', true)
 44→      .single();
 45→
 46→    if (!keyRecord) {
 47→      return new Response(JSON.stringify({ error: 'Invalid API key' }), {
 48→        status: 401,
 49→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
 50→      });
 51→    }
 52→
 53→    if ((keyRecord as any).merchants?.plan !== 'business') {
 54→      return new Response(
 55→        JSON.stringify({ error: 'Business plan required' }),
 56→        {
 57→          status: 403,
 58→          headers: { ...corsHeaders, 'Content-Type': 'application/json' },
 59→        }
 60→      );
 61→    }
 62→
 63→    const merchantId = keyRecord.merchant_id;
 64→
 65→    // Update last_used_at
 66→    await supabase
 67→      .from('api_keys')
 68→      .update({ last_used_at: new Date().toISOString() })
 69→      .eq('id', keyRecord.id);
 70→
 71→    // Route requests
 72→    const url = new URL(req.url);
 73→    const path = url.pathname.replace(/^\/api-v1\/?/, '').replace(/\/$/, '');
 74→    const method = req.method;
 75→
 76→    const json = (data: any, status = 200) =>
 77→      new Response(JSON.stringify(data), {
 78→        status,
 79→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
 80→      });
 81→
 82→    // GET /programs — List merchant's loyalty programs
 83→    if (method === 'GET' && path === 'programs') {
 84→      const { data } = await supabase
 85→        .from('loyalty_programs')
 86→        .select('*')
 87→        .eq('merchant_id', merchantId);
 88→      return json({ data });
 89→    }
 90→
 91→    // GET /clients — List merchant's clients via customer_cards
 92→    if (method === 'GET' && path === 'clients') {
 93→      const { data } = await supabase
 94→        .from('customer_cards')
 95→        .select('*, customers(*), loyalty_programs!inner(merchant_id)')
 96→        .eq('loyalty_programs.merchant_id', merchantId);
 97→      return json({ data });
 98→    }
 99→
100→    // POST /stamps — Add stamp to a customer card
101→    if (method === 'POST' && path === 'stamps') {
102→      const body = await req.json();
103→      if (!body.card_id) return json({ error: 'Missing card_id' }, 400);
104→      const count = body.count ?? 1;
105→
106→      const { data: card } = await supabase
107→        .from('customer_cards')
108→        .select('*, loyalty_programs!inner(merchant_id)')
109→        .eq('id', body.card_id)
110→        .eq('loyalty_programs.merchant_id', merchantId)
111→        .single();
112→      if (!card) return json({ error: 'Card not found' }, 404);
113→
114→      await supabase
115→        .from('customer_cards')
116→        .update({
117→          current_stamps: card.current_stamps + count,
118→          last_activity: new Date().toISOString(),
119→        })
120→        .eq('id', card.id);
121→
122→      await supabase.from('transactions').insert({
123→        card_id: card.id,
124→        type: 'stamp_add',
125→        value: count,
126→        validated_by: 'manual',
127→      });
128→
129→      return json({ success: true });
130→    }
131→
132→    // POST /points — Add points to a customer card
133→    if (method === 'POST' && path === 'points') {
134→      const body = await req.json();
135→      if (!body.card_id || !body.points) {
136→        return json({ error: 'Missing card_id or points' }, 400);
137→      }
138→
139→      const { data: card } = await supabase
140→        .from('customer_cards')
141→        .select('*, loyalty_programs!inner(merchant_id)')
142→        .eq('id', body.card_id)
143→        .eq('loyalty_programs.merchant_id', merchantId)
144→        .single();
145→      if (!card) return json({ error: 'Card not found' }, 404);
146→
147→      await supabase
148→        .from('customer_cards')
149→        .update({
150→          current_points: card.current_points + body.points,
151→          last_activity: new Date().toISOString(),
152→        })
153→        .eq('id', card.id);
154→
155→      await supabase.from('transactions').insert({
156→        card_id: card.id,
157→        type: 'points_add',
158→        value: body.points,
159→        validated_by: 'manual',
160→      });
161→
162→      return json({ success: true });
163→    }
164→
165→    // GET /analytics — Get merchant KPIs
166→    if (method === 'GET' && path === 'analytics') {
167→      const { data } = await supabase
168→        .from('merchant_kpis')
169→        .select('*')
170→        .eq('merchant_id', merchantId)
171→        .single();
172→      return json({ data });
173→    }
174→
175→    return json({ error: 'Not found' }, 404);
176→  } catch (err) {
177→    return new Response(JSON.stringify({ error: (err as Error).message }), {
178→      status: 500,
179→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
180→    });
181→  }
182→});
