 1→import { NextResponse } from 'next/server';
 2→import Stripe from 'stripe';
 3→import { createClient as createSupabaseAdmin } from '@supabase/supabase-js';
 4→
 5→const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
 6→
 7→// Use admin client (service role) for webhook processing
 8→function getAdminClient() {
 9→  return createSupabaseAdmin(
10→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
11→    process.env.SUPABASE_SERVICE_ROLE_KEY!
12→  );
13→}
