 1→import { NextResponse } from 'next/server';
 2→import Stripe from 'stripe';
 3→import { createClient } from '@/lib/supabase/server';
 4→
 5→const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
 6→
 7→const PRICE_IDS: Record<string, string> = {
 8→  pro: process.env.STRIPE_PRO_PRICE_ID!,
 9→  business: process.env.STRIPE_BUSINESS_PRICE_ID!,
10→};
11→
12→export async function POST(req: Request) {
13→  const { plan } = await req.json();
14→  if (!plan || !PRICE_IDS[plan]) {
15→    return NextResponse.json({ error: 'Invalid plan' }, { status: 400 });
16→  }
17→
18→  const supabase = await createClient();
19→  const {
20→    data: { user },
21→  } = await supabase.auth.getUser();
22→  if (!user)
23→    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
24→
25→  const { data: merchant } = await supabase
26→    .from('merchants')
27→    .select('*')
28→    .eq('user_id', user.id)
29→    .single();
30→  if (!merchant)
31→    return NextResponse.json({ error: 'Merchant not found' }, { status: 404 });
32→
33→  let customerId = merchant.stripe_customer_id;
34→  if (!customerId) {
35→    const customer = await stripe.customers.create({
36→      email: user.email,
37→      metadata: { merchant_id: merchant.id },
38→    });
39→    customerId = customer.id;
40→    await supabase
41→      .from('merchants')
42→      .update({ stripe_customer_id: customerId })
43→      .eq('id', merchant.id);
44→  }
45→
46→  const session = await stripe.checkout.sessions.create({
47→    customer: customerId,
48→    mode: 'subscription',
49→    line_items: [{ price: PRICE_IDS[plan], quantity: 1 }],
50→    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/subscription?success=true`,
51→    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/subscription?cancelled=true`,
52→  });
53→
54→  return NextResponse.json({ url: session.url });
55→}
