 1→import { useEffect, useRef } from 'react';
 2→import * as Notifications from 'expo-notifications';
 3→import * as Device from 'expo-device';
 4→import { Platform } from 'react-native';
 5→import { supabase } from '../lib/supabase';
 6→import { useAuthStore } from '../lib/store';
 7→
 8→Notifications.setNotificationHandler({
 9→  handleNotification: async () => ({
10→    shouldShowAlert: true,
11→    shouldPlaySound: true,
12→    shouldSetBadge: true,
13→  }),
14→});
15→
16→export function useNotifications() {
17→  const session = useAuthStore((s) => s.session);
18→  const notificationListener = useRef<Notifications.EventSubscription>();
19→  const responseListener = useRef<Notifications.EventSubscription>();
20→
21→  useEffect(() => {
22→    if (!session) return;
23→
24→    async function register() {
25→      if (!Device.isDevice) return;
26→
27→      const { status: existing } = await Notifications.getPermissionsAsync();
28→      let finalStatus = existing;
29→      if (existing !== 'granted') {
30→        const { status } = await Notifications.requestPermissionsAsync();
31→        finalStatus = status;
32→      }
33→      if (finalStatus !== 'granted') return;
34→
35→      const tokenData = await Notifications.getExpoPushTokenAsync();
36→      const token = tokenData.data;
37→
38→      await supabase.from('customers').update({ push_token: token }).eq('id', session.user.id);
39→    }
40→
41→    register();
42→
43→    notificationListener.current = Notifications.addNotificationReceivedListener(() => {});
44→    responseListener.current = Notifications.addNotificationResponseReceivedListener(() => {});
45→
46→    return () => {
47→      notificationListener.current?.remove();
48→      responseListener.current?.remove();
49→    };
50→  }, [session]);
51→}
