 1→import { useEffect } from 'react';
 2→import * as Location from 'expo-location';
 3→import { supabase } from '../lib/supabase';
 4→import { useAuthStore } from '../lib/store';
 5→
 6→export function useLocation() {
 7→  const session = useAuthStore((s) => s.session);
 8→
 9→  useEffect(() => {
10→    if (!session) return;
11→
12→    let subscription: Location.LocationSubscription;
13→
14→    async function start() {
15→      const { status } = await Location.requestForegroundPermissionsAsync();
16→      if (status !== 'granted') return;
17→
18→      subscription = await Location.watchPositionAsync(
19→        { accuracy: Location.Accuracy.Balanced, distanceInterval: 200 },
20→        async (location) => {
21→          await supabase.functions.invoke('proximity-check', {
22→            body: {
23→              lat: location.coords.latitude,
24→              lng: location.coords.longitude,
25→            },
26→          });
27→        }
28→      );
29→    }
30→
31→    start();
32→    return () => { subscription?.remove(); };
33→  }, [session]);
34→}
