 36→async function hashKey(key: string): Promise<string> {
 37→  const encoder = new TextEncoder();
 38→  const data = encoder.encode(key);
 39→  const hash = await crypto.subtle.digest('SHA-256', data);
 40→  return Array.from(new Uint8Array(hash))
 41→    .map((b) => b.toString(16).padStart(2, '0'))
 42→    .join('');
 43→}
 44→
 45→function generateApiKey(): string {
 46→  const bytes = new Uint8Array(16);
 47→  crypto.getRandomValues(bytes);
 48→  const hex = Array.from(bytes)
 49→    .map((b) => b.toString(16).padStart(2, '0'))
 50→    .join('');
 51→  return `lk_${hex}`;
 52→}
