 66→  const fetchApiKeys = useCallback(
 67→    async (mId: string) => {
 68→      const { data } = await supabase
 69→        .from('api_keys')
 70→        .select('id, name, last_used_at, is_active, created_at')
 71→        .eq('merchant_id', mId)
 72→        .order('created_at', { ascending: false });
 73→      setApiKeys(data ?? []);
 74→    },
 75→    [supabase]
 76→  );
 77→
 78→  useEffect(() => {
 79→    async function init() {
 80→      const {
 81→        data: { user },
 82→      } = await supabase.auth.getUser();
 83→      if (!user) return;
 84→      const { data: merchant } = await supabase
