 1→create or replace function public.check_program_limit()
 2→returns trigger as $$
 3→declare merchant_plan text; program_count int;
 4→begin
 5→  select plan into merchant_plan from merchants where id = new.merchant_id;
 6→  select count(*) into program_count from loyalty_programs where merchant_id = new.merchant_id;
 7→  if merchant_plan = 'free' and program_count >= 1 then raise exception 'Free plan: 1 program max'; end if;
 8→  if merchant_plan = 'pro' and program_count >= 3 then raise exception 'Pro plan: 3 programs max'; end if;
 9→  return new;
10→end;
11→$$ language plpgsql;
12→
13→create trigger check_program_limit_trigger
14→  before insert on public.loyalty_programs
15→  for each row execute function public.check_program_limit();
