  1→import { useState } from 'react';
  2→import { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';
  3→import { CameraView, useCameraPermissions } from 'expo-camera';
  4→import { useTranslation } from 'react-i18next';
  5→import { supabase } from '../../lib/supabase';
  6→import { useNfc } from '../../hooks/useNfc';
  7→import { NfcScanner } from '../../components/nfc-scanner';
