  9→type ScanMode = 'qr' | 'nfc';
 10→
 11→export default function ScanScreen() {
 12→  const [permission, requestPermission] = useCameraPermissions();
 13→  const [scanned, setScanned] = useState(false);
 14→  const [processing, setProcessing] = useState(false);
 15→  const [mode, setMode] = useState<ScanMode>('qr');
 16→  const [nfcScanning, setNfcScanning] = useState(false);
 17→  const { t } = useTranslation();
 18→  const { supported: nfcSupported, readTag } = useNfc();
 19→
 20→  async function handleScanResult(data: string) {
 21→    if (processing) return;
 22→    setProcessing(true);
 23→
 24→    try {
 25→      const payload = JSON.parse(data);
 26→      if (!payload.qr_id || !payload.secret) {
 27→        Alert.alert(t('scan.error'), 'Invalid scan data.');
 28→        return;
 29→      }
 30→
 31→      const { data: result, error } = await supabase.functions.invoke('validate-scan', {
 32→        body: { qr_id: payload.qr_id, secret: payload.secret },
 33→      });
 34→
 35→      if (error) throw error;
 36→
 37→      if (result.success) {
 38→        const msg = result.type === 'stamp'
 39→          ? `Stamp added! ${result.new_total}/${result.goal}`
 40→          : `+${result.added} points! Total: ${result.new_total}`;
 41→        Alert.alert(t('scan.success'), msg);
 42→      } else {
 43→        Alert.alert(t('common.error'), result.error || t('scan.error'));
 44→      }
 45→    } catch (e: any) {
 46→      Alert.alert(t('common.error'), e.message || t('scan.error'));
 47→    } finally {
 48→      setProcessing(false);
 49→      setTimeout(() => setScanned(false), 2000);
 50→    }
 51→  }
 52→
 53→  async function handleBarCodeScanned({ data }: { data: string }) {
 54→    if (scanned || processing) return;
 55→    setScanned(true);
 56→
 57→    try {
 58→      const payload = JSON.parse(data);
 59→      if (payload.type !== 'loyalty_scan') {
 60→        Alert.alert(t('scan.error'), 'This is not a loyalty QR code.');
 61→        return;
 62→      }
 63→    } catch {
 64→      Alert.alert(t('scan.error'), 'Invalid QR code.');
 65→      return;
 66→    }
 67→
 68→    await handleScanResult(data);
 69→  }
 70→
 71→  async function handleNfcScan() {
 72→    if (nfcScanning || processing) return;
 73→    setNfcScanning(true);
 74→
 75→    try {
 76→      const data = await readTag();
 77→      if (data) {
 78→        await handleScanResult(data);
 79→      } else {
 80→        Alert.alert(t('scan.error'), 'No NFC data found. Try again.');
 81→      }
 82→    } finally {
 83→      setNfcScanning(false);
 84→    }
 85→  }
 86→
 87→  function renderModeToggle() {
 88→    return (
 89→      <View style={styles.toggleContainer}>
 90→        <TouchableOpacity
 91→          style={[styles.toggleButton, mode === 'qr' && styles.toggleActive]}
 92→          onPress={() => setMode('qr')}
 93→        >
 94→          <Text style={[styles.toggleText, mode === 'qr' && styles.toggleTextActive]}>
 95→            QR Code
 96→          </Text>
 97→        </TouchableOpacity>
 98→        {nfcSupported && (
 99→          <TouchableOpacity
100→            style={[styles.toggleButton, mode === 'nfc' && styles.toggleActive]}
101→            onPress={() => setMode('nfc')}
102→          >
103→            <Text style={[styles.toggleText, mode === 'nfc' && styles.toggleTextActive]}>
104→              NFC
105→            </Text>
106→          </TouchableOpacity>
107→        )}
108→      </View>
109→    );
110→  }
111→
112→  if (mode === 'nfc') {
113→    return (
114→      <View style={styles.container}>
115→        {renderModeToggle()}
116→        <NfcScanner scanning={nfcScanning} />
117→        <View style={styles.nfcButtonContainer}>
118→          <TouchableOpacity
119→            style={[styles.button, (nfcScanning || processing) && styles.buttonDisabled]}
120→            onPress={handleNfcScan}
121→            disabled={nfcScanning || processing}
122→          >
123→            <Text style={styles.buttonText}>
124→              {nfcScanning ? 'Scanning...' : 'Start NFC Scan'}
125→            </Text>
126→          </TouchableOpacity>
127→        </View>
128→      </View>
129→    );
130→  }
131→
132→  if (!permission) return <View />;
133→  if (!permission.granted) {
134→    return (
135→      <View style={styles.center}>
136→        {renderModeToggle()}
137→        <Text style={styles.text}>Camera permission is required to scan QR codes</Text>
138→        <TouchableOpacity style={styles.button} onPress={requestPermission}>
139→          <Text style={styles.buttonText}>Grant Permission</Text>
140→        </TouchableOpacity>
141→      </View>
142→    );
143→  }
144→
145→  return (
146→    <View style={styles.container}>
147→      {renderModeToggle()}
148→      <CameraView
149→        style={styles.camera}
150→        barcodeScannerSettings={{ barcodeTypes: ['qr'] }}
151→        onBarcodeScanned={scanned ? undefined : handleBarCodeScanned}
152→      >
153→        <View style={styles.overlay}>
154→          <View style={styles.frame} />
155→          <Text style={styles.hint}>{processing ? t('common.loading') : t('scan.scanning')}</Text>
156→        </View>
157→      </CameraView>
158→    </View>
159→  );
160→}
