 39→          ? card.current_stamps >= (r.stamps_required || 0)
 40→          : card.current_points >= (r.points_cost || 0);
 41→        items.push({
 42→          ...r,
 43→          program_name: program.name,
 44→          program_type: program.type,
 45→          card_id: card.id,
