 9→  const {
10→    data: { user },
11→  } = await supabase.auth.getUser();
12→  if (!user)
13→    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
14→
15→  const { data: merchant } = await supabase
16→    .from('merchants')
