26→  }
27→
28→  const session = await stripe.billingPortal.sessions.create({
29→    customer: merchant.stripe_customer_id,
30→    return_url: `${process.env.NEXT_PUBLIC_APP_URL}/subscription`,
31→  });
32→
33→  return NextResponse.json({ url: session.url });
34→}
