 11→export default function SettingsPage() {
 12→  const supabase = createClient();
 13→  const [merchant, setMerchant] = useState<any>(null);
 14→  const [loading, setLoading] = useState(false);
 15→  const [name, setName] = useState('');
 16→  const [address, setAddress] = useState('');
 17→  const [category, setCategory] = useState('');
 18→  const [phone, setPhone] = useState('');
 19→  const [hours, setHours] = useState('');
 20→  const [logoUrl, setLogoUrl] = useState('');
 21→  const [message, setMessage] = useState('');
 22→
 23→  useEffect(() => {
 24→    fetchMerchant();
 25→  }, []);
 26→
 27→  async function fetchMerchant() {
 28→    const { data: { user } } = await supabase.auth.getUser();
 29→    if (!user) return;
 30→    const { data } = await supabase.from('merchants').select('*').eq('user_id', user.id).single();
 31→    if (data) {
 32→      setMerchant(data);
 33→      setName(data.name || '');
 34→      setAddress(data.address || '');
 35→      setCategory(data.category || '');
 36→      setPhone(data.phone || '');
 37→      setHours(data.opening_hours || '');
 38→      setLogoUrl(data.logo_url || '');
 39→    }
 40→  }
 41→
 42→  async function handleSave() {
 43→    if (!merchant) return;
 44→    setLoading(true);
 45→    await supabase.from('merchants').update({
 46→      name, address, category, phone, opening_hours: hours, logo_url: logoUrl,
 47→    }).eq('id', merchant.id);
 48→    setMessage('Settings saved!');
 49→    setLoading(false);
 50→    setTimeout(() => setMessage(''), 3000);
 51→  }
 52→
 53→  async function handleLogoUpload(e: React.ChangeEvent<HTMLInputElement>) {
 54→    const file = e.target.files?.[0];
 55→    if (!file || !merchant) return;
 56→    const path = `${merchant.id}/${Date.now()}-${file.name}`;
 57→    const { error } = await supabase.storage.from('logos').upload(path, file);
 58→    if (error) return;
 59→    const { data: { publicUrl } } = supabase.storage.from('logos').getPublicUrl(path);
 60→    setLogoUrl(publicUrl);
 61→  }
 62→
 63→  async function handleDeleteAccount() {
 64→    if (!confirm('Are you sure you want to delete your account? This action cannot be undone.')) return;
 65→    if (!merchant) return;
 66→    await supabase.from('merchants').delete().eq('id', merchant.id);
 67→    await supabase.auth.signOut();
 68→    window.location.href = '/login';
 69→  }
 70→
 71→  return (
 72→    <div className="space-y-6 max-w-2xl">
 73→      <h1 className="text-2xl font-bold">Settings</h1>
 74→      {message && <p className="text-green-600 text-sm">{message}</p>}
 75→
 76→      <Card>
 77→        <CardHeader><CardTitle>Business Logo</CardTitle></CardHeader>
 78→        <CardContent className="space-y-3">
 79→          {logoUrl && <img src={logoUrl} alt="Logo" className="w-24 h-24 object-cover rounded" />}
 80→          <Input type="file" accept="image/*" onChange={handleLogoUpload} />
 81→        </CardContent>
 82→      </Card>
 83→
 84→      <Card>
 85→        <CardHeader><CardTitle>Store Information</CardTitle></CardHeader>
 86→        <CardContent className="space-y-3">
 87→          <div><Label>Store Name</Label><Input value={name} onChange={e => setName(e.target.value)} /></div>
 88→          <div><Label>Address</Label><Input value={address} onChange={e => setAddress(e.target.value)} /></div>
 89→          <div><Label>Category</Label><Input value={category} onChange={e => setCategory(e.target.value)} placeholder="e.g. Restaurant, Retail, Cafe" /></div>
 90→          <div><Label>Phone</Label><Input value={phone} onChange={e => setPhone(e.target.value)} /></div>
 91→          <div><Label>Opening Hours</Label><Textarea value={hours} onChange={e => setHours(e.target.value)} placeholder={'Mon-Fri: 9:00-18:00\nSat: 10:00-16:00'} /></div>
 92→          <Button onClick={handleSave} disabled={loading}>{loading ? 'Saving...' : 'Save Changes'}</Button>
 93→        </CardContent>
 94→      </Card>
 95→
 96→      <Card>
 97→        <CardHeader><CardTitle>Manage</CardTitle></CardHeader>
 98→        <CardContent className="space-y-2">
 99→          <Link href="/settings/locations" className="block text-blue-600 hover:underline">Manage Locations &rarr;</Link>
100→          <Link href="/settings/api" className="block text-blue-600 hover:underline">API Keys (Business plan) &rarr;</Link>
101→        </CardContent>
102→      </Card>
103→
104→      <Card className="border-red-200">
105→        <CardHeader><CardTitle className="text-red-600">Danger Zone</CardTitle></CardHeader>
106→        <CardContent>
107→          <p className="text-sm text-gray-500 mb-3">Permanently delete your merchant account and all associated data.</p>
108→          <Button variant="destructive" onClick={handleDeleteAccount}>Delete Account</Button>
109→        </CardContent>
110→      </Card>
111→    </div>
112→  );
113→}
